1	'use strict';
2	// 두 도구(claude·codex)의 설정 홈 경로와 동기화 대상 위치를 정의한다.
3	// (과거 gemini도 지원했으나 사용자 결정으로 전면 제거 — 2모델 체제.)
4	// 모드(mode.js)에 따라 읽는 곳이 갈린다:
5	//  - dummy : 프로젝트 안 fixtures/ (실제 파일 안 건드림)
6	//  - real  : 실제 ~/.claude 등 (사용자가 토글을 켤 때만)
7	// canonical/backups도 모드별로 분리해 더미 데이터와 실제 데이터가 섞이지 않게 한다.
8	
9	const os = require('os');
10	const path = require('path');
11	const mode = require('./mode');
12	
13	const PROJECT = path.join(__dirname, '..');
14	
15	function home() {
16	  return os.homedir();
17	}
18	
19	// 더미 모드에서 읽을 fixtures 루트
20	function fixturesRoot() {
21	  return process.env.AAD_FIXTURES || path.join(PROJECT, 'fixtures');
22	}
23	
24	// 각 도구의 설정 홈 디렉토리 (모드에 따라 fixtures vs 실제 홈)
25	function toolHomes() {
26	  if (mode.getMode() === 'dummy') {
27	    const f = fixturesRoot();
28	    return {
29	      claude: path.join(f, 'claude'),
30	      codex: path.join(f, 'codex'),
31	    };
32	  }
33	  return {
34	    claude: path.join(home(), '.claude'),
35	    codex: path.join(home(), '.codex'),
36	  };
37	}
38	
39	// 지시문 트랙: 도구별 글로벌 지시문 파일명 (canonical 1벌 → 파일명만 바꿔 배포)
40	const INSTRUCTION_FILENAME = {
41	  claude: 'CLAUDE.md',
42	  codex: 'AGENTS.md',
43	};
44	
45	const TOOLS = ['claude', 'codex'];
46	
47	// 도구의 글로벌 지시문 파일 절대 경로
48	function instructionPath(tool) {
49	  return path.join(toolHomes()[tool], INSTRUCTION_FILENAME[tool]);
50	}
51	
52	// agent 트랙: 도구별 agent 폴더와 파일 확장자/경로
53	//  - Claude: .md (frontmatter + 본문) / Codex: .toml (developer_instructions)  ← 0번 검증
54	function agentDir(tool) {
55	  return path.join(toolHomes()[tool], 'agents');
56	}
57	function agentExt(tool) {
58	  return tool === 'codex' ? '.toml' : '.md';
59	}
60	function agentPath(tool, name) {
61	  return path.join(agentDir(tool), name + agentExt(tool));
62	}
63	
64	// skill 트랙 (D11):
65	//  - .agents/skills = 여러 도구가 공유하는 cross-tool 표준 위치(에이전트 소속 아님)
66	//  - ~/.codex/skills = 공식 문서엔 없는 비공식 위치(실재) → official:false로 표시
67	function agentsHome() {
68	  return mode.getMode() === 'dummy' ? path.join(fixturesRoot(), 'agents') : path.join(home(), '.agents');
69	}
70	
71	// 스캔할 skill 소스 목록. official=false면 사용자에게 "비공식"으로 알린다.
72	function skillSources() {
73	  const h = toolHomes();
74	  return [
75	    { id: 'claude-user', tool: 'claude', dir: path.join(h.claude, 'skills'), official: true },
76	    { id: 'claude-plugins', tool: 'claude', dir: path.join(h.claude, 'plugins'), official: true, plugin: true, recursive: true },
77	    { id: 'shared-agents', tool: 'shared', dir: path.join(agentsHome(), 'skills'), official: true, shared: true },
78	    { id: 'codex-native', tool: 'codex', dir: path.join(h.codex, 'skills'), official: false },
79	  ];
80	}
81	
82	// push(쓰기) 대상 디렉토리 — 공식 위치 기준
83	function skillTargetDir(tool) {
84	  const h = toolHomes();
85	  if (tool === 'claude') return path.join(h.claude, 'skills');
86	  if (tool === 'codex') return path.join(agentsHome(), 'skills'); // 공식 USER 위치
87	  throw new Error('알 수 없는 도구: ' + tool);
88	}
89	
90	// canonical 저장소 위치 (프로젝트 안 — D5). 모드별로 분리(더미/실제 데이터 안 섞이게).
91	function canonicalRoot() {
92	  if (process.env.AAD_CANONICAL) return process.env.AAD_CANONICAL;
93	  return mode.getMode() === 'dummy'
94	    ? path.join(PROJECT, '.dummy', 'canonical')
95	    : path.join(PROJECT, 'canonical');
96	}
97	
98	// 배포본 덮어쓰기 전 백업을 모아둘 폴더 (모드별 분리)
99	function backupRoot() {
100	  if (process.env.AAD_BACKUPS) return process.env.AAD_BACKUPS;
101	  return mode.getMode() === 'dummy'
102	    ? path.join(PROJECT, '.dummy', 'backups')
103	    : path.join(PROJECT, 'backups');
104	}
105	
106	// 번들 정적 카탈로그(스토어). 모드 무관 — 실제 사용자 데이터가 아니라 프로젝트에 포함된
107	// 큐레이션 목록이다(외부 통신 없음). 환경변수로 오버라이드 가능.
108	function catalogPath() {
109	  return process.env.AAD_CATALOG || path.join(PROJECT, 'catalog', 'catalog.json');
110	}
111	
112	// ─── 프로젝트 스코프 (T1) ───
113	// 저장소(프로젝트) 레벨 skill/agent/지시문 위치.
114	// 근거: docs/verification/project-scope-verification.md (0번 검증 — 공식 문서 확인 완료).
115	
116	// 등록된 프로젝트 목록(projects.json) 저장 위치.
117	// canonicalRoot()가 이미 모드별(.dummy/canonical vs canonical)로 분리돼 있어
118	// 더미/실제 레지스트리가 자동으로 격리된다.
119	function projectsFile() {
120	  return path.join(canonicalRoot(), 'projects.json');
121	}
122	
123	// 프로젝트 레벨 skill 소스 목록 — skillSources() 항목과 같은 형태에
124	// scope:'project' 와 projectRoot 를 더한다.
125	//  - claude: <root>/.claude/skills  (공식)
126	//  - shared: <root>/.agents/skills  (cross-tool 표준 — Codex 공식 위치.
127	//    ※ .codex/skills 는 공식 문서에 없어 만들지 않는다 — 0번 검증)
128	function projectSkillSources(root) {
129	  return [
130	    { id: 'claude-project', tool: 'claude', dir: path.join(root, '.claude', 'skills'), official: true, scope: 'project', projectRoot: root },
131	    { id: 'shared-project', tool: 'shared', dir: path.join(root, '.agents', 'skills'), official: true, shared: true, scope: 'project', projectRoot: root },
132	  ];
133	}
134	
135	// 프로젝트 레벨 agent 폴더 — 파일 확장자는 글로벌과 동일하게 agentExt(tool) 사용.
136	//  - claude: <root>/.claude/agents/*.md / codex: <root>/.codex/agents/*.toml
137	function projectAgentDir(root, tool) {
138	  if (tool === 'claude') return path.join(root, '.claude', 'agents');
139	  if (tool === 'codex') return path.join(root, '.codex', 'agents');
140	  throw new Error('알 수 없는 도구: ' + tool);
141	}
142	
143	// 프로젝트 지시문 파일 후보 경로 (도구별 배열 — 존재 확인은 호출자 몫).
144	//  - Claude는 두 위치 모두 공식("either ./CLAUDE.md or ./.claude/CLAUDE.md").
145	function projectInstructionPaths(root) {
146	  return {
147	    claude: [path.join(root, 'CLAUDE.md'), path.join(root, '.claude', 'CLAUDE.md')],
148	    codex: [path.join(root, 'AGENTS.md')],
149	  };
150	}
151	
152	// "최초 1회" 프로젝트 스캔의 기본 루트.
153	//  - dummy: fixtures/projects (가짜 프로젝트만 — 실제 디스크 안 훑음)
154	//  - real : 사용자 홈 디렉토리
155	function projectScanDefaultRoot() {
156	  return mode.getMode() === 'dummy' ? path.join(fixturesRoot(), 'projects') : home();
157	}
158	
159	// ─── 원격 레지스트리 (스토어-R1) ───
160	// 등록된 레지스트리 목록(registries.json) 저장 위치.
161	// canonicalRoot()가 모드별(.dummy/canonical vs canonical)로 분리돼 있어
162	// 더미/실제 레지스트리가 자동으로 격리된다(projectsFile과 동일 패턴).
163	function registriesFile() {
164	  return path.join(canonicalRoot(), 'registries.json');
165	}
166	
167	// 레지스트리 clone/파싱 캐시 디렉토리. 번들 원본(catalog.json)은 건드리지 않고
168	// 여기(catalog/cache)에만 registry-<id>.json 및 임시 clone을 둔다.
169	function registryCacheDir() {
170	  return process.env.AAD_REGISTRY_CACHE || path.join(PROJECT, 'catalog', 'cache');
171	}
172	
173	module.exports = {
174	  TOOLS,
175	  catalogPath,
176	  INSTRUCTION_FILENAME,
177	  toolHomes,
178	  instructionPath,
179	  agentDir,
180	  agentExt,
181	  agentPath,
182	  agentsHome,
183	  skillSources,
184	  skillTargetDir,
185	  canonicalRoot,
186	  backupRoot,
187	  // 프로젝트 스코프 (T1)
188	  projectsFile,
189	  projectSkillSources,
190	  projectAgentDir,
191	  projectInstructionPaths,
192	  projectScanDefaultRoot,
193	  // 원격 레지스트리 (스토어-R1)
194	  registriesFile,
195	  registryCacheDir,
196	};
